78	function createModuleLoader() {
79	  const jitiLoaders = new Map<string, ReturnType<typeof createJiti>>();
80	
81	  return (modulePath: string) => {
82	    const tryNative = shouldPreferNativeJiti(modulePath);
83	    const aliasMap = buildPluginLoaderAliasMap(modulePath, process.argv[1], import.meta.url);
84	    const cacheKey = JSON.stringify({
85	      tryNative,
86	      aliasMap: Object.entries(aliasMap).toSorted(([left], [right]) => left.localeCompare(right)),
87	    });
88	    const cached = jitiLoaders.get(cacheKey);
89	    if (cached) {
90	      return cached;
91	    }
92	    const loader = createJiti(import.meta.url, {
93	      ...buildPluginLoaderJitiOptions(aliasMap),
94	      tryNative,
95	    });
96	    jitiLoaders.set(cacheKey, loader);
97	    return loader;
98	  };
99	}
