### 11. INBOUND MESSAGE HANDLING (src/inbound.ts)

**Pattern (IRC example):**
```typescript
async function deliverIrcReply(params: {
  payload: OutboundReplyPayload;
  target: string;
  accountId: string;
  sendReply?: (target: string, text: string, replyToId?: string) => Promise<void>;
  statusSink?: (patch: { lastOutboundAt?: number }) => void;
}) {
  const delivered = await deliverFormattedTextWithAttachments({
    payload: params.payload,
    send: async ({ text, replyToId }) => {
      if (params.sendReply) {
        await params.sendReply(params.target, text, replyToId);
      } else {
        await sendMessageIrc(params.target, text, {
          accountId: params.accountId,
          replyTo: replyToId,
        });
      }
      params.statusSink?.({ lastOutboundAt: Date.now() });
    },
  });
}
```

**Nostr pattern:**
```typescript
onMessage: async (senderPubkey, text, reply, meta) => {
  const resolvedAccess = await resolveInboundAccess(senderPubkey, text);
  if (resolvedAccess.access.decision !== "allow") {
    return;  // Drop message
  }

  await dispatchInboundDirectDmWithRuntime({
    cfg: ctx.cfg,
    runtime,
    channel: "nostr",
    accountId: account.accountId,
    peer: { kind: "direct", id: senderPubkey },
    senderId: senderPubkey,
    rawBody: text,
    messageId: meta.eventId,
    timestamp: meta.createdAt * 1000,
    deliver: async (payload) => {
      const outboundText = payload?.text ?? "";
      await reply(outboundText);
    },
  });
}
