### 12. PROVIDER MONITORING (src/monitor.ts)

**Pattern:**
```typescript
export async function monitor[Channel]Provider(params: {
  accountId: string;
  config: CoreConfig;
  runtime: PluginRuntime;
  abortSignal: AbortSignal;
  statusSink: StatusSink;
}): Promise<void> {
  const account = resolve[Channel]Account({ cfg: params.config, accountId: params.accountId });

  // Connect to service
  const connection = await connect(account);

  // Listen for messages
  connection.on("message", async (msg) => {
    // Dispatch to inbound handler
    await handleInboundMessage(msg);
  });

  // Handle cleanup
  params.abortSignal.addEventListener("abort", () => {
    connection.close();
  });
}
```

