### 13. HEALTH PROBING (src/probe.ts)

**Pattern:**
```typescript
export async function probe[Channel](
  cfg: CoreConfig,
  opts: { accountId?: string; timeoutMs?: number },
): Promise<Probe> {
  const account = resolve[Channel]Account({ cfg, accountId: opts.accountId });

  if (!account.configured) {
    return {
      status: "unconfigured",
      reason: "Missing required fields",
    };
  }

  try {
    // Attempt connection/check
    const result = await checkConnection(account, opts.timeoutMs);
    return {
      status: "ok",
      connectedAt: Date.now(),
      ...result,
    };
  } catch (error) {
    return {
      status: "error",
      error: String(error),
    };
  }
}
```

