### 14. NORMALIZATION & TARGETING (src/normalize.ts)

**IRC example:**
```typescript
export function normalizeIrcMessagingTarget(input: string): string | null {
  const trimmed = input.trim();
  if (!trimmed) return null;

  // Remove control chars
  const cleaned = trimmed.replace(/[\x00-\x1F\x7F]/g, "");

  // Validate: channel starts with # or &, otherwise is nick
  if (cleaned.startsWith("#") || cleaned.startsWith("&")) {
    return cleaned;
  }

  // Return as nick (user)
  return cleaned;
}

export function looksLikeIrcTargetId(input: string): boolean {
  const trimmed = input.trim();
  return trimmed.startsWith("#") || trimmed.startsWith("&") || /^[a-zA-Z0-9_\-]+$/.test(trimmed);
}

export function isChannelTarget(target: string): boolean {
  return target.startsWith("#") || target.startsWith("&");
}
```

**Nostr example:**
```typescript
export function normalizeNostrMessagingTarget(target: string): string | null {
  const cleaned = target.trim().replace(/^nostr:/i, "");
  try {
    return normalizePubkey(cleaned);  // Validate & lowercase hex
  } catch {
    return null;
  }
}

export function looksLikeNostrTargetId(input: string): boolean {
  const trimmed = input.trim();
  return (
    trimmed.startsWith("npub1") ||
    /^[0-9a-fA-F]{64}$/.test(trimmed)
  );
}
```

