├── src/
│   ├── channel.ts                    # Main channel plugin definition (createChatChannelPlugin)
│   ├── channel.setup.ts              # Setup-only plugin (Telegram only, separate setup)
│   ├── accounts.ts                   # Account resolution & listing helpers
