### 10. MESSAGE SENDING (src/send.ts)

**IRC example:**
```typescript
export async function sendMessageIrc(
  to: string,
  text: string,
  opts: SendIrcOptions = {},
): Promise<SendIrcResult> {
  const runtime = getIrcRuntime();
  const cfg = opts.cfg ?? runtime.config.loadConfig();
  const account = resolveIrcAccount({ cfg, accountId: opts.accountId });

  if (!account.configured) {
    throw new Error("IRC not configured");
  }

  const target = normalizeIrcMessagingTarget(to);
  const tableMode = resolveMarkdownTableMode({ cfg, channel: "irc", accountId });
  const prepared = convertMarkdownTables(text.trim(), tableMode);

  // Connect or use existing client
  const client = await connectIrcClient(buildIrcConnectOptions(account));

  // Send message
  if (isChannelTarget(target)) {
    client.write(`PRIVMSG ${target} :${prepared}`);
  } else {
    client.write(`PRIVMSG ${target} :${prepared}`);
  }

  return {
    messageId: makeIrcMessageId(),
    target,
  };
}
```

**Nostr example:**
```typescript
sendText: async ({ cfg, to, text, accountId }) => {
  const core = getNostrRuntime();
  const bus = activeBuses.get(accountId ?? DEFAULT_ACCOUNT_ID);
  if (!bus) {
    throw new Error(`Nostr bus not running for account ${accountId}`);
  }
  const normalizedTo = normalizePubkey(to);
  await bus.sendDm(normalizedTo, text);
  return attachChannelToResult("nostr", {
    to: normalizedTo,
    messageId: `nostr-${Date.now()}`,
  });
}
```

