253	
254	interface RelayHealthStats {
255	  successCount: number;
256	  failureCount: number;
257	  latencySum: number;
258	  latencyCount: number;
259	  lastSuccess: number;
260	  lastFailure: number;
261	}
262	
263	interface RelayHealthTracker {
264	  /** Record a successful operation */
265	  recordSuccess: (relay: string, latencyMs: number) => void;
266	  /** Record a failed operation */
267	  recordFailure: (relay: string) => void;
268	  /** Get health score (0-1, higher is better) */
269	  getScore: (relay: string) => number;
270	  /** Get relays sorted by health (best first) */
271	  getSortedRelays: (relays: string[]) => string[];
272	}
273	
274	function createRelayHealthTracker(): RelayHealthTracker {
275	  const stats = new Map<string, RelayHealthStats>();
276	
277	  function getOrCreate(relay: string): RelayHealthStats {
278	    let s = stats.get(relay);
279	    if (!s) {
280	      s = {
281	        successCount: 0,
282	        failureCount: 0,
283	        latencySum: 0,
284	        latencyCount: 0,
285	        lastSuccess: 0,
286	        lastFailure: 0,
287	      };
288	      stats.set(relay, s);
289	    }
290	    return s;
291	  }
292	
293	  return {
294	    recordSuccess(relay: string, latencyMs: number): void {
295	      const s = getOrCreate(relay);
296	      s.successCount++;
297	      s.latencySum += latencyMs;
298	      s.latencyCount++;
299	      s.lastSuccess = Date.now();
300	    },

