832	/**
833	 * Check if a string looks like a valid Nostr pubkey (hex or npub)
834	 */
835	export function isValidPubkey(input: string): boolean {
836	  if (typeof input !== "string") {
837	    return false;
838	  }
839	  const trimmed = input.trim();
840	
841	  // npub format
842	  if (trimmed.startsWith("npub1")) {
843	    try {
844	      const decoded = nip19.decode(trimmed);
845	      return decoded.type === "npub";
846	    } catch {
847	      return false;
848	    }
849	  }
850	
851	  // Hex format
852	  return /^[0-9a-fA-F]{64}$/.test(trimmed);
853	}
854	
855	/**
856	 * Normalize a pubkey to hex format (accepts npub or hex)
857	 */
858	export function normalizePubkey(input: string): string {
859	  const trimmed = input.trim();
860	
861	  // npub format - decode to hex
862	  if (trimmed.startsWith("npub1")) {
863	    const decoded = nip19.decode(trimmed);
864	    if (decoded.type !== "npub") {
865	      throw new Error("Invalid npub key");
866	    }
867	    // Convert Uint8Array to hex string
868	    return Array.from(decoded.data as unknown as Uint8Array)
869	      .map((b) => b.toString(16).padStart(2, "0"))
870	      .join("");
871	  }
872	
873	  // Already hex - validate and return lowercase
874	  if (!/^[0-9a-fA-F]{64}$/.test(trimmed)) {
875	    throw new Error("Pubkey must be 64 hex characters or npub format");
876	  }
877	  return trimmed.toLowerCase();
878	}
879	
880	/**
881	 * Convert a hex pubkey to npub format
882	 */
883	export function pubkeyToNpub(hexPubkey: string): string {
884	  const normalized = normalizePubkey(hexPubkey);
885	  // npubEncode expects a hex string, not Uint8Array
886	  return nip19.npubEncode(normalized);
887	}
