export const PULSEBOARD_PREFIX = "pulseboard:";

export function normalizePulseBoardTarget(raw: string): string | null {
  // Strip "pulseboard:" prefix if present
  // "#board-name"  → "#board-name"  (group/board)
  // "@username"    → "@username"    (direct message)
  // "username"     → "@username"    (normalize bare usernames)
  // Returns null for empty / invalid input
}

export function looksLikePulseBoardTargetId(input: string): boolean {
