### Step 11 — `src/send.ts`

Thin function over native `fetch`. Called from `channel.ts` outbound adapter.

```typescript
export type SendPulseBoardOptions = {
  accountId?: string;
  cfg?: CoreConfig;
};

export type SendPulseBoardResult = {
  to: string;
  messageId: string;
};

export async function sendMessagePulseBoard(
  to: string,
  text: string,
  opts: SendPulseBoardOptions = {},
): Promise<SendPulseBoardResult> {
  const runtime = getPulseBoardRuntime();
  const cfg = opts.cfg ?? runtime.config.loadConfig();
  const account = resolvePulseBoardAccount({ cfg, accountId: opts.accountId });

  if (!account.configured || !account.token) {
    throw new Error("PulseBoard is not configured");
  }

  const normalized = normalizePulseBoardTarget(to);
  if (!normalized) throw new Error(`Invalid PulseBoard target: ${to}`);

  // POST to /api/v1/boards/{boardId}/messages  OR  /api/v1/users/{userId}/messages
  const path = isBoardTarget(normalized)
    ? `/api/v1/boards/${encodeURIComponent(normalized.slice(1))}/messages`
    : `/api/v1/users/${encodeURIComponent(normalized.slice(1))}/messages`;

  const res = await fetch(`${account.serverUrl}${path}`, {
    method: "POST",
    headers: {
      Authorization: `Bearer ${account.token}`,
      "Content-Type": "application/json",
    },
    body: JSON.stringify({ text }),
  });

  if (!res.ok) {
    throw new Error(`PulseBoard send failed: HTTP ${res.status}`);
  }

  const body = (await res.json()) as { id: string };
  runtime.channel.activity.record({ direction: "outbound", accountId: account.accountId });

  return { to: normalized, messageId: body.id };
}
```

