export type PulseBoardProbeResult =
  | { status: "ok"; username: string; latencyMs: number }
  | { status: "unconfigured"; reason: string }
  | { status: "error"; error: string };

export async function probePulseBoard(
  cfg: CoreConfig,
  opts: { accountId?: string; timeoutMs?: number } = {},
): Promise<PulseBoardProbeResult> {
  const account = resolvePulseBoardAccount({ cfg, accountId: opts.accountId });
  if (!account.configured || !account.token) {
    return { status: "unconfigured", reason: "token and username are required" };
  }
  // GET /api/v1/me with timeout → { status: "ok", username, latencyMs }
  // On network error → { status: "error", error: ... }
}
