export async function monitorPulseBoardProvider(params: {
  accountId: string;
  config: CoreConfig;
  runtime: PluginRuntime;
  abortSignal: AbortSignal;
  statusSink: (patch: object) => void;
  onMessage: (event: PulseBoardInboundEvent) => Promise<void>;
}): Promise<void> {
  // Loop: GET /api/v1/updates?since=<lastSeenMs>
  // Parse each event:  { id, type: "board_message"|"direct_message", from, target, text, ts }
  // Call params.onMessage(event)
  // On abort: break
  // On error: exponential backoff, update statusSink with error
}

export type PulseBoardInboundEvent = {
  id: string;
  type: "board_message" | "direct_message";
  from: string;      // "@username" of sender
  target: string;    // "#board-name" or "@bot-username" for DMs
  text: string;
  ts: number;        // Unix ms
};
```

