### Step 17 — `src/channel.ts` (main plugin)

Uses `createChatChannelPlugin` from `openclaw/plugin-sdk/core`.

```typescript
import { createChatChannelPlugin, ... } from "openclaw/plugin-sdk/core";
import { createChannelDirectoryAdapter, createComputedAccountStatusAdapter,
         createScopedDmSecurityResolver, runStoppablePassiveMonitor,
         dispatchInboundDirectDmWithRuntime, dispatchInboundGroupMessageWithRuntime,
         attachChannelToResult } from "openclaw/plugin-sdk/...";

export const pulseBoardPlugin = createChatChannelPlugin({
  base: {
    id: "pulseboard",
    meta: { /* matches package.json channel block */ },
    capabilities: {
      chatTypes: ["direct", "group"],
      media: false,
    },
    reload: { configPrefixes: ["channels.pulseboard"] },
    configSchema: pulseBoardChannelConfigSchema,
    setup: pulseBoardSetupAdapter,
    setupWizard: pulseBoardSetupWizard,

    config: {
      listAccountIds: (cfg) => listPulseBoardAccountIds(cfg),
      resolveAccount: (cfg, accountId) => resolvePulseBoardAccount({ cfg, accountId }),
      isConfigured: (account) => account.configured,
    },

    messaging: {
      normalizeTarget: normalizePulseBoardTarget,
      resolveOutboundSessionRoute: resolvePulseBoardOutboundSessionRoute,
      targetResolver: {
        looksLikeId: looksLikePulseBoardTargetId,
        hint: "<#board-name|@username>",
      },
    },

    directory: createChannelDirectoryAdapter({
      listPeers: async ({ cfg, accountId }) => {
        // Return allowFrom users as directory entries
      },
      listGroups: async ({ cfg, accountId }) => {
        // Return configured boards as directory entries
      },
    }),

    status: createComputedAccountStatusAdapter({
      probeAccount: async ({ cfg, account, timeoutMs }) =>
        probePulseBoard(cfg, { accountId: account.accountId, timeoutMs }),
      resolveAccountSnapshot: ({ account }) => ({
        configured: account.configured,
        label: account.username ?? account.accountId,
      }),
    }),

    gateway: {
      startAccount: async (ctx) => {
        const account = resolvePulseBoardAccount({ cfg: ctx.cfg, accountId: ctx.accountId });
        if (!account.configured) return;

        await runStoppablePassiveMonitor({
          abortSignal: ctx.abortSignal,
          start: async () => {
            await monitorPulseBoardProvider({
              accountId: account.accountId,
              config: ctx.cfg,
              runtime: ctx.runtime,
              abortSignal: ctx.abortSignal,
              statusSink: ctx.statusSink,
              onMessage: async (event) => {
                const isBoard = event.type === "board_message";
                if (isBoard) {
                  await dispatchInboundGroupMessageWithRuntime({
                    cfg: ctx.cfg, runtime: ctx.runtime,
                    channel: "pulseboard",
                    accountId: account.accountId,
                    group: { kind: "group", id: event.target },
                    senderId: event.from,
                    rawBody: event.text,
                    messageId: event.id,
                    timestamp: event.ts,
                    deliver: async (payload) => {
                      await sendMessagePulseBoard(event.target, payload?.text ?? "", {
                        accountId: account.accountId, cfg: ctx.cfg,
                      });
                    },
                  });
                } else {
                  await dispatchInboundDirectDmWithRuntime({
                    cfg: ctx.cfg, runtime: ctx.runtime,
                    channel: "pulseboard",
                    accountId: account.accountId,
                    peer: { kind: "direct", id: event.from },
                    senderId: event.from,
                    rawBody: event.text,
                    messageId: event.id,
                    timestamp: event.ts,
                    deliver: async (payload) => {
                      await sendMessagePulseBoard(event.from, payload?.text ?? "", {
                        accountId: account.accountId, cfg: ctx.cfg,
                      });
                    },
                  });
                }
              },
            });
          },
        });
      },
    },
  },

  security: {
    resolveDmPolicy: createScopedDmSecurityResolver({
      channelKey: "pulseboard",
      resolvePolicy: (account) => account.config.dmPolicy,
      resolveAllowFrom: (account) => account.config.allowFrom,
      policyPathSuffix: "dmPolicy",
      normalizeEntry: normalizePulseBoardAllowEntry,
    }),
  },

  pairing: {
    text: {
      idLabel: "PulseBoard username",
      message: "You have been approved to send messages to this assistant.",
      normalizeAllowEntry: normalizePulseBoardAllowEntry,
      notify: async ({ id, accountId, cfg }) => {
        await sendMessagePulseBoard(id, "You have been approved.", { accountId, cfg });
      },
    },
  },

  outbound: {
    deliveryMode: "direct",
    textChunkLimit: 4000,
    chunkerMode: "text",
    sendText: async ({ cfg, to, text, accountId }) => {
      const result = await sendMessagePulseBoard(to, text, { accountId, cfg });
      return attachChannelToResult("pulseboard", result);
    },
  },
});
```

