```typescript
import {
  buildChannelOutboundSessionRoute,
  stripChannelTargetPrefix,
  type ChannelOutboundSessionRouteParams,
} from "openclaw/plugin-sdk/core";

export function resolvePulseBoardOutboundSessionRoute(
  params: ChannelOutboundSessionRouteParams,
) {
  const target = stripChannelTargetPrefix(params.target, "pulseboard");
  if (!target) return null;

  const normalized = normalizePulseBoardTarget(target);
  if (!normalized) return null;

  const chatType = isBoardTarget(normalized) ? "group" : "direct";

  return buildChannelOutboundSessionRoute({
    cfg: params.cfg,
    agentId: params.agentId,
    channel: "pulseboard",
    accountId: params.accountId,
    peer: { kind: chatType, id: normalized },
    chatType,
    from: `pulseboard:${normalized}`,
    to: `pulseboard:${normalized}`,
  });
}
```

