1	import type { ResolvedIrcAccount } from "./accounts.js";
2	import { normalizeIrcAllowlist, resolveIrcAllowlistMatch } from "./normalize.js";
3	import {
4	  resolveIrcMentionGate,
5	  resolveIrcGroupAccessGate,
6	  resolveIrcGroupMatch,
7	  resolveIrcGroupSenderAllowed,
8	  resolveIrcRequireMention,
9	} from "./policy.js";
10	import {
11	  GROUP_POLICY_BLOCKED_LABEL,
12	  createChannelPairingController,
13	  deliverFormattedTextWithAttachments,
14	  dispatchInboundReplyWithBase,
15	  logInboundDrop,
16	  isDangerousNameMatchingEnabled,
17	  readStoreAllowFromForDmPolicy,
18	  resolveControlCommandGate,
19	  resolveAllowlistProviderRuntimeGroupPolicy,
20	  resolveDefaultGroupPolicy,
21	  resolveEffectiveAllowFromLists,
22	  warnMissingProviderGroupPolicyFallbackOnce,
23	  type OutboundReplyPayload,
24	  type OpenClawConfig,
25	  type RuntimeEnv,
26	} from "./runtime-api.js";
27	import { getIrcRuntime } from "./runtime.js";
28	import { sendMessageIrc } from "./send.js";
29	import type { CoreConfig, IrcInboundMessage } from "./types.js";
30	
31	const CHANNEL_ID = "irc" as const;
32	
33	const escapeIrcRegexLiteral = (value: string) => value.replace(/[.*+?^${}()|[\]\\]/g, "\\$&");
34	
35	function resolveIrcEffectiveAllowlists(params: {
36	  configAllowFrom: string[];
37	  configGroupAllowFrom: string[];
38	  storeAllowList: string[];
39	  dmPolicy: string;
40	}): {
41	  effectiveAllowFrom: string[];
42	  effectiveGroupAllowFrom: string[];
43	} {
44	  const { effectiveAllowFrom, effectiveGroupAllowFrom } = resolveEffectiveAllowFromLists({
45	    allowFrom: params.configAllowFrom,
46	    groupAllowFrom: params.configGroupAllowFrom,
47	    storeAllowFrom: params.storeAllowList,
48	    dmPolicy: params.dmPolicy,
49	    // IRC intentionally requires explicit groupAllowFrom; do not fallback to allowFrom.
50	    groupAllowFromFallbackToAllowFrom: false,
51	  });
52	  return { effectiveAllowFrom, effectiveGroupAllowFrom };
53	}
54	
55	async function deliverIrcReply(params: {
56	  payload: OutboundReplyPayload;
57	  target: string;
58	  accountId: string;
59	  sendReply?: (target: string, text: string, replyToId?: string) => Promise<void>;
60	  statusSink?: (patch: { lastOutboundAt?: number }) => void;
61	}) {
62	  const delivered = await deliverFormattedTextWithAttachments({
63	    payload: params.payload,
64	    send: async ({ text, replyToId }) => {
65	      if (params.sendReply) {
66	        await params.sendReply(params.target, text, replyToId);
67	      } else {
68	        await sendMessageIrc(params.target, text, {
69	          accountId: params.accountId,
70	          replyTo: replyToId,
71	        });
72	      }
73	      params.statusSink?.({ lastOutboundAt: Date.now() });
74	    },
75	  });
76	  if (!delivered) {
77	    return;
78	  }
79	}
80	
81	export async function handleIrcInbound(params: {
82	  message: IrcInboundMessage;
83	  account: ResolvedIrcAccount;
84	  config: CoreConfig;
85	  runtime: RuntimeEnv;
86	  connectedNick?: string;
87	  sendReply?: (target: string, text: string, replyToId?: string) => Promise<void>;
88	  statusSink?: (patch: { lastInboundAt?: number; lastOutboundAt?: number }) => void;
89	}): Promise<void> {
90	  const { message, account, config, runtime, connectedNick, statusSink } = params;
91	  const core = getIrcRuntime();
92	  const pairing = createChannelPairingController({
93	    core,
94	    channel: CHANNEL_ID,
95	    accountId: account.accountId,
96	  });
97	
98	  const rawBody = message.text?.trim() ?? "";
99	  if (!rawBody) {
100	    return;
101	  }
102	
103	  statusSink?.({ lastInboundAt: message.timestamp });
104	
105	  const senderDisplay = message.senderHost
106	    ? `${message.senderNick}!${message.senderUser ?? "?"}@${message.senderHost}`
107	    : message.senderNick;
108	  const allowNameMatching = isDangerousNameMatchingEnabled(account.config);
109	
110	  const dmPolicy = account.config.dmPolicy ?? "pairing";
111	  const defaultGroupPolicy = resolveDefaultGroupPolicy(config);
112	  const { groupPolicy, providerMissingFallbackApplied } =
113	    resolveAllowlistProviderRuntimeGroupPolicy({
114	      providerConfigPresent: config.channels?.irc !== undefined,
115	      groupPolicy: account.config.groupPolicy,
116	      defaultGroupPolicy,
117	    });
118	  warnMissingProviderGroupPolicyFallbackOnce({
119	    providerMissingFallbackApplied,
120	    providerKey: "irc",
121	    accountId: account.accountId,
122	    blockedLabel: GROUP_POLICY_BLOCKED_LABEL.channel,
123	    log: (message) => runtime.log?.(message),
124	  });
125	
126	  const configAllowFrom = normalizeIrcAllowlist(account.config.allowFrom);
127	  const configGroupAllowFrom = normalizeIrcAllowlist(account.config.groupAllowFrom);
128	  const storeAllowFrom = await readStoreAllowFromForDmPolicy({
129	    provider: CHANNEL_ID,
130	    accountId: account.accountId,
131	    dmPolicy,
132	    readStore: pairing.readStoreForDmPolicy,
133	  });
134	  const storeAllowList = normalizeIrcAllowlist(storeAllowFrom);
135	
136	  const groupMatch = resolveIrcGroupMatch({
137	    groups: account.config.groups,
138	    target: message.target,
139	  });
140	
141	  if (message.isGroup) {
142	    const groupAccess = resolveIrcGroupAccessGate({ groupPolicy, groupMatch });
143	    if (!groupAccess.allowed) {
144	      runtime.log?.(`irc: drop channel ${message.target} (${groupAccess.reason})`);
145	      return;
146	    }
147	  }
148	
149	  const directGroupAllowFrom = normalizeIrcAllowlist(groupMatch.groupConfig?.allowFrom);
150	  const wildcardGroupAllowFrom = normalizeIrcAllowlist(groupMatch.wildcardConfig?.allowFrom);
151	  const groupAllowFrom =
152	    directGroupAllowFrom.length > 0 ? directGroupAllowFrom : wildcardGroupAllowFrom;
