575	function removeTopLevelChannelConfigSection<Config extends OpenClawConfig>(params: {
576	  cfg: Config;
577	  sectionKey: string;
578	}): Config {
579	  const nextChannels = { ...params.cfg.channels } as Record<string, unknown>;
580	  delete nextChannels[params.sectionKey];
581	  const nextCfg = { ...params.cfg };
582	  if (Object.keys(nextChannels).length > 0) {
583	    nextCfg.channels = nextChannels as Config["channels"];
584	  } else {
585	    delete nextCfg.channels;
586	  }
587	  return nextCfg;
588	}
