590	function clearTopLevelChannelConfigFields<Config extends OpenClawConfig>(params: {
591	  cfg: Config;
592	  sectionKey: string;
593	  clearBaseFields: string[];
594	}): Config {
595	  const section = params.cfg.channels?.[params.sectionKey] as Record<string, unknown> | undefined;
596	  if (!section) {
597	    return params.cfg;
598	  }
599	  const nextSection = { ...section };
600	  for (const field of params.clearBaseFields) {
601	    delete nextSection[field];
602	  }
603	  return {
604	    ...params.cfg,
605	    channels: {
606	      ...params.cfg.channels,
607	      [params.sectionKey]: nextSection,
608	    },
609	  } as Config;
610	}
