120	function normalizeLocalE164(number: string): string {
121	  const withoutPrefix = number.replace(/^whatsapp:/i, "").trim();
122	  const digits = withoutPrefix.replace(/[^\d+]/g, "");
123	  if (digits.startsWith("+")) {
124	    return `+${digits.slice(1)}`;
125	  }
126	  return `+${digits}`;
127	}
