204	export function authorizeConfigWrite(params: {
205	  cfg: OpenClawConfig;
206	  origin?: ConfigWriteScope;
207	  target?: ConfigWriteTarget;
208	  allowBypass?: boolean;
209	}): ConfigWriteAuthorizationResult {
210	  if (params.allowBypass) {
211	    return { allowed: true };
212	  }
213	  if (params.target?.kind === "ambiguous") {
214	    return { allowed: false, reason: "ambiguous-target" };
215	  }
216	  if (
217	    params.origin?.channelId &&
218	    !resolveChannelConfigWrites({
219	      cfg: params.cfg,
220	      channelId: params.origin.channelId,
221	      accountId: params.origin.accountId,
222	    })
223	  ) {
224	    return {
225	      allowed: false,
226	      reason: "origin-disabled",
227	      blockedScope: { kind: "origin", scope: params.origin },
228	    };
229	  }
230	  const seen = new Set<string>();
231	  for (const target of listConfigWriteTargetScopes(params.target)) {
232	    if (!target.channelId) {
233	      continue;
234	    }
235	    const key = `${target.channelId}:${normalizeAccountId(target.accountId)}`;
236	    if (seen.has(key)) {
237	      continue;
238	    }
239	    seen.add(key);
240	    if (
241	      !resolveChannelConfigWrites({
242	        cfg: params.cfg,
243	        channelId: target.channelId,
244	        accountId: target.accountId,
245	      })
246	    ) {
247	      return {
248	        allowed: false,
249	        reason: "target-disabled",
250	        blockedScope: { kind: "target", scope: target },
251	      };
252	    }
253	  }
254	  return { allowed: true };
