623	  clearBaseFields?: string[];
624	}): Pick<
625	  ChannelConfigAdapter<ResolvedAccount>,
626	  | "listAccountIds"
627	  | "resolveAccount"
628	  | "inspectAccount"
629	  | "defaultAccountId"
630	  | "setAccountEnabled"
631	  | "deleteAccount"
632	> {
