655	        ? clearTopLevelChannelConfigFields({
656	            cfg: cfg as Config,
657	            sectionKey: params.sectionKey,
658	            clearBaseFields: params.clearBaseFields ?? [],
659	          })
660	        : removeTopLevelChannelConfigSection({
661	            cfg: cfg as Config,
662	            sectionKey: params.sectionKey,
663	          });
664	    },
665	  };
666	}
