import type { BaseProbeResult } from "openclaw/plugin-sdk/channel-contract";
import type { GroupToolPolicyConfig } from "openclaw/plugin-sdk/channel-policy";
import type { OpenClawConfig } from "openclaw/plugin-sdk/core";
import type { DmPolicy, GroupPolicy } from "openclaw/plugin-sdk/setup";

export type PulseBoardBoardConfig = {
  enabled?: boolean;
  allowFrom?: Array<string | number>;
  requireMention?: boolean;
  tools?: GroupToolPolicyConfig;
};

export type PulseBoardAccountConfig = {
  name?: string;
  enabled?: boolean;
  /** Bearer token for the PulseBoard REST API (sensitive). */
  token?: string;
  /** File path containing the bearer token. */
  tokenFile?: string;
  /** PulseBoard username (used as sender id in the API). */
  username?: string;
  /** Base URL of the PulseBoard server, e.g. https://boards.example.com */
  serverUrl?: string;
  /** Board ids to monitor for inbound messages (e.g. ["#general"]). */
  boards?: string[];
  dmPolicy?: DmPolicy;
  allowFrom?: Array<string | number>;
  defaultTo?: string;
  groupPolicy?: GroupPolicy;
  groupAllowFrom?: Array<string | number>;
  /** Per-board config keyed by board id (e.g. "#general"). */
  groups?: Record<string, PulseBoardBoardConfig>;
  textChunkLimit?: number;
};

export type PulseBoardConfig = PulseBoardAccountConfig & {
  accounts?: Record<string, PulseBoardAccountConfig>;
  defaultAccount?: string;
};

export type CoreConfig = OpenClawConfig & {
  channels?: OpenClawConfig["channels"] & {
    pulseboard?: PulseBoardConfig;
  };
};

export type PulseBoardInboundMessage = {
  messageId: string;
  /** Conversation peer id: board id (#board-name) for groups, sender username for DMs. */
  target: string;
  senderId: string;
  senderUsername: string;
  text: string;
  timestamp: number;
  isGroup: boolean;
};

export type PulseBoardProbe = BaseProbeResult<string> & {
  serverUrl: string;
  username: string;
  connected: boolean;
};

