const PULSEBOARD_TARGET_PATTERN = /^[#@]?[a-zA-Z0-9_-]+$/u;

/** Returns true if the target is a board (starts with #). */
export function isBoardTarget(target: string): boolean {
  return target.startsWith("#");
}

/** Returns true if the target is a direct-message user (starts with @). */
export function isDmTarget(target: string): boolean {
  return target.startsWith("@");
}

/** Strip recognized PulseBoard target prefixes and return the normalized id. */
export function normalizePulseBoardMessagingTarget(raw: string): string | undefined {
  const trimmed = raw.trim();
  if (!trimmed) {
    return undefined;
  }
  let target = trimmed;
  const lowered = target.toLowerCase();
  if (lowered.startsWith("pulseboard:")) {
    target = target.slice("pulseboard:".length).trim();
  }
  if (target.toLowerCase().startsWith("board:")) {
    target = target.slice("board:".length).trim();
    if (!target.startsWith("#")) {
      target = `#${target}`;
    }
  }
  if (target.toLowerCase().startsWith("user:")) {
    target = target.slice("user:".length).trim();
  }
  if (!target || !looksLikePulseBoardTargetId(target)) {
    return undefined;
  }
  return target;
}

/** Returns true when the string looks like a valid PulseBoard target id. */
export function looksLikePulseBoardTargetId(raw: string): boolean {
  const trimmed = raw.trim();
  if (!trimmed) {
    return false;
  }
  return PULSEBOARD_TARGET_PATTERN.test(trimmed);
}

/** Normalize a single allowlist entry: lowercase, strip known prefixes. */
export function normalizePulseBoardAllowEntry(raw: string): string {
  let value = raw.trim().toLowerCase();
  if (!value) {
    return "";
  }
  if (value.startsWith("pulseboard:")) {
    value = value.slice("pulseboard:".length);
  }
  if (value.startsWith("user:")) {
    value = value.slice("user:".length);
  }
  // Strip leading @ for username comparisons.
  value = value.replace(/^@/, "");
  return value.trim();
}

/** Normalize a list of allowlist entries. */
export function normalizePulseBoardAllowlist(entries?: Array<string | number>): string[] {
  return (entries ?? []).map((entry) => normalizePulseBoardAllowEntry(String(entry))).filter(Boolean);
}

/** Ensure the board id has a leading # prefix. */
export function normalizePulseBoardBoardId(raw: string): string {
  const trimmed = raw.trim();
  if (!trimmed) {
    return "";
  }
  if (trimmed.startsWith("#")) {
    return trimmed;
  }
  return `#${trimmed}`;
}

/** Check whether a sender is in the effective allowlist (supports wildcard "*"). */
export function resolvePulseBoardSenderAllowed(params: {
  senderId: string;
  allowFrom: string[];
}): boolean {
  const normalized = params.senderId.trim().toLowerCase().replace(/^@/, "");
  const allowSet = new Set(
    params.allowFrom
      .map((entry) => entry.trim().toLowerCase().replace(/^@/, ""))
      .filter(Boolean),
  );
  if (allowSet.has("*")) {
    return true;
  }
  return allowSet.has(normalized);
}

