/** Normalize a list of allowlist entries. */
export function normalizePulseBoardAllowlist(entries?: Array<string | number>): string[] {
  return (entries ?? []).map((entry) => normalizePulseBoardAllowEntry(String(entry))).filter(Boolean);
}

/** Ensure the board id has a leading # prefix. */
export function normalizePulseBoardBoardId(raw: string): string {
  const trimmed = raw.trim();
  if (!trimmed) {
    return "";
  }
  if (trimmed.startsWith("#")) {
    return trimmed;
  }
  return `#${trimmed}`;
}

/** Check whether a sender is in the effective allowlist (supports wildcard "*"). */
export function resolvePulseBoardSenderAllowed(params: {
  senderId: string;
  allowFrom: string[];
}): boolean {
  const normalized = params.senderId.trim().toLowerCase().replace(/^@/, "");
  const allowSet = new Set(
    params.allowFrom
      .map((entry) => entry.trim().toLowerCase().replace(/^@/, ""))
      .filter(Boolean),
  );
  if (allowSet.has("*")) {
    return true;
  }
  return allowSet.has(normalized);
}

