import { resolvePulseBoardAccount } from "./accounts.js";
import { isBoardTarget, normalizePulseBoardMessagingTarget } from "./normalize.js";
import { getPulseBoardRuntime } from "./runtime.js";
import type { CoreConfig } from "./types.js";

export type SendPulseBoardResult = {
  messageId: string;
  target: string;
};

type SendPulseBoardOptions = {
  cfg?: CoreConfig;
  accountId?: string;
};

function recordPulseBoardOutboundActivity(accountId: string): void {
  try {
    getPulseBoardRuntime().channel.activity.record({
      channel: "pulseboard",
      accountId,
      direction: "outbound",
    });
  } catch (error) {
    if (!(error instanceof Error) || error.message !== "PulseBoard runtime not initialized") {
      throw error;
    }
  }
}

export async function sendMessagePulseBoard(
  to: string,
  text: string,
  opts: SendPulseBoardOptions = {},
): Promise<SendPulseBoardResult> {
  const runtime = getPulseBoardRuntime();
  const cfg = (opts.cfg ?? runtime.config.loadConfig()) as CoreConfig;
  const account = resolvePulseBoardAccount({
    cfg,
    accountId: opts.accountId,
  });

  if (!account.configured) {
    throw new Error(
      `PulseBoard is not configured for account "${account.accountId}" (need token, serverUrl, and username in channels.pulseboard).`,
    );
  }

  const normalized = normalizePulseBoardMessagingTarget(to);
  if (!normalized) {
    throw new Error(`Invalid PulseBoard target: ${to}`);
  }

  const target = normalized;
  const payload = text.trim();
  if (!payload) {
    throw new Error("Message must be non-empty for PulseBoard sends");
  }

  const isGroup = isBoardTarget(target);
  // Board ids start with #, strip for URL path segment.
  const targetId = isGroup ? target.slice(1) : target.replace(/^@/, "");
  const endpoint = isGroup
    ? `${account.serverUrl}/api/v1/boards/${encodeURIComponent(targetId)}/messages`
    : `${account.serverUrl}/api/v1/users/${encodeURIComponent(targetId)}/messages`;

  const res = await fetch(endpoint, {
    method: "POST",
    headers: {
      "Content-Type": "application/json",
      Authorization: `Bearer ${account.token}`,
    },
    body: JSON.stringify({ text: payload }),
  });

  if (!res.ok) {
    throw new Error(`PulseBoard send failed: HTTP ${res.status} ${res.statusText}`);
  }

  const json = (await res.json()) as { messageId?: string };
  const messageId = json.messageId ?? `pb-${Date.now()}`;

  recordPulseBoardOutboundActivity(account.accountId);

  return { messageId, target };
}

