import { dispatchInboundDirectDmWithRuntime, logInboundDrop } from "openclaw/plugin-sdk/channel-inbound";
import { createChannelPairingController } from "openclaw/plugin-sdk/channel-pairing";
import {
  readStoreAllowFromForDmPolicy,
  resolveEffectiveAllowFromLists,
} from "openclaw/plugin-sdk/channel-policy";
import { resolveLoggerBackedRuntime } from "openclaw/plugin-sdk/extension-shared";
import { resolveAllowlistProviderRuntimeGroupPolicy } from "openclaw/plugin-sdk/runtime-group-policy";
import type { PluginRuntime } from "openclaw/plugin-sdk/core";
import { resolvePulseBoardAccount } from "./accounts.js";
import {
  normalizePulseBoardAllowlist,
  normalizePulseBoardBoardId,
  resolvePulseBoardSenderAllowed,
} from "./normalize.js";
import { sendMessagePulseBoard } from "./send.js";
import type { CoreConfig, PulseBoardInboundMessage } from "./types.js";

// Pairing approval message sent when a pairing challenge is confirmed.
const PAIRING_APPROVED_MESSAGE =
  "✅ Pairing approved. You can now send messages to this agent.";

export type PulseBoardMonitorOptions = {
  accountId?: string;
  config?: CoreConfig;
  runtime?: PluginRuntime;
  abortSignal?: AbortSignal;
  statusSink?: (patch: { lastInboundAt?: number; lastOutboundAt?: number }) => void;
};

type PulseBoardUpdatePayload = {
  messages?: Array<{
    messageId: string;
    target: string;
    senderId: string;
    senderUsername: string;
    text: string;
    timestamp: number;
    isGroup: boolean;
  }>;
};

async function fetchUpdates(params: {
  serverUrl: string;
  token: string;
  since: number;
  abortSignal?: AbortSignal;
}): Promise<PulseBoardUpdatePayload> {
  const url = `${params.serverUrl}/api/v1/updates?since=${params.since}`;
  const res = await fetch(url, {
    headers: { Authorization: `Bearer ${params.token}` },
    signal: params.abortSignal,
  });
  if (!res.ok) {
    throw new Error(`PulseBoard updates fetch failed: HTTP ${res.status} ${res.statusText}`);
  }
  return (await res.json()) as PulseBoardUpdatePayload;
}

async function dispatchPulseBoardMessage(params: {
  message: PulseBoardInboundMessage;
  core: PluginRuntime;
  cfg: CoreConfig;
  accountId: string;
  username: string;
  statusSink?: (patch: { lastInboundAt?: number; lastOutboundAt?: number }) => void;
}): Promise<void> {
  const { message, core, cfg, accountId, username, statusSink } = params;
  const isGroup = message.isGroup;
  const extraContext = isGroup
    ? {
        ChatType: "group" as const,
        GroupSubject: message.target,
        SenderName: message.senderUsername,
      }
    : undefined;

  await dispatchInboundDirectDmWithRuntime({
    cfg,
    runtime: core as Parameters<typeof dispatchInboundDirectDmWithRuntime>[0]["runtime"],
    channel: "pulseboard",
    channelLabel: "PulseBoard",
    accountId,
    peer: { kind: "direct", id: message.target },
    senderId: message.senderId,
    senderAddress: `pulseboard:${message.senderUsername}`,
    recipientAddress: `pulseboard:${username}`,
    conversationLabel: isGroup ? message.target : message.senderUsername,
    rawBody: message.text,
    messageId: message.messageId,
    timestamp: message.timestamp,
    ...(extraContext ? { extraContext } : {}),
    deliver: async (payload) => {
      const deliverText = typeof payload === "string" ? payload : (payload as { text?: string }).text ?? "";
      if (!deliverText.trim()) {
        return;
      }
      await sendMessagePulseBoard(message.target, deliverText, { cfg, accountId });
      statusSink?.({ lastOutboundAt: Date.now() });
    },
    onRecordError: (err) => {
      core.logging.getChildLogger().warn?.(`[pulseboard:${accountId}] session record error: ${String(err)}`);
    },
    onDispatchError: (err) => {
      core.logging.getChildLogger().error(`[pulseboard:${accountId}] dispatch error: ${String(err)}`);
    },
  });
}

export async function monitorPulseBoardProvider(opts: PulseBoardMonitorOptions): Promise<{ stop: () => void }> {
  const core = opts.runtime ?? (() => { throw new Error("PulseBoard runtime not initialized"); })();
  const cfg = opts.config ?? (core.config.loadConfig() as CoreConfig);
  const account = resolvePulseBoardAccount({
    cfg,
    accountId: opts.accountId,
  });

  const runtime = resolveLoggerBackedRuntime(
    opts.runtime,
    core.logging.getChildLogger(),
  );

  if (!account.configured) {
    throw new Error(
      `PulseBoard is not configured for account "${account.accountId}" (need token, serverUrl, and username in channels.pulseboard).`,
    );
  }

  const logger = core.logging.getChildLogger({
    channel: "pulseboard",
    accountId: account.accountId,
  });

  const pairingController = createChannelPairingController({
    core: core as Parameters<typeof createChannelPairingController>[0]["core"],
    channel: "pulseboard",
    accountId: account.accountId,
  });

  let stopped = false;
  let since = Date.now();

  logger.info(
    `[${account.accountId}] starting PulseBoard monitor (${account.serverUrl} as ${account.username})`,
  );

  // Long-poll loop: run until stopped.
  (async () => {
    while (!stopped && !opts.abortSignal?.aborted) {
      try {
        const payload = await fetchUpdates({
          serverUrl: account.serverUrl,
          token: account.token,
          since,
          abortSignal: opts.abortSignal,
        });

        const messages = payload.messages ?? [];
        if (messages.length > 0) {
          since = Math.max(since, ...messages.map((m) => m.timestamp + 1));
        }

        for (const msg of messages) {
          if (stopped || opts.abortSignal?.aborted) {
            break;
          }
          // Skip messages from ourselves.
          if (msg.senderUsername.toLowerCase() === account.username.toLowerCase()) {
            continue;
          }

          core.channel.activity.record({
            channel: "pulseboard",
            accountId: account.accountId,
            direction: "inbound",
            at: msg.timestamp,
          });
          opts.statusSink?.({ lastInboundAt: msg.timestamp });

          const message: PulseBoardInboundMessage = {
            messageId: msg.messageId,
            target: msg.isGroup ? normalizePulseBoardBoardId(msg.target) : msg.target,
            senderId: msg.senderId,
            senderUsername: msg.senderUsername,
            text: msg.text,
            timestamp: msg.timestamp,
            isGroup: msg.isGroup,
          };

          if (message.isGroup) {
            // Check board access policy.
            const groupPolicy = resolveAllowlistProviderRuntimeGroupPolicy({
              providerConfigPresent: cfg.channels?.pulseboard !== undefined,
              groupPolicy: account.config.groupPolicy,
            });
            if (groupPolicy.groupPolicy === "disabled") {
              logInboundDrop({
                channel: "pulseboard",
                accountId: account.accountId,
                reason: "group policy disabled",
                target: message.target,
              });
              continue;
            }
            if (groupPolicy.groupPolicy === "allowlist") {
              const allowedBoards = account.config.boards ?? [];
              const allowedBoardsNorm = allowedBoards.map((b) => normalizePulseBoardBoardId(b).toLowerCase());
              if (
                allowedBoards.length > 0 &&
                !allowedBoardsNorm.includes(message.target.toLowerCase())
              ) {
                logInboundDrop({
                  channel: "pulseboard",
                  accountId: account.accountId,
                  reason: "board not in allowlist",
                  target: message.target,
                });
                continue;
              }
            }
          } else {
            // Check DM policy.
            const dmPolicy = account.config.dmPolicy ?? "pairing";
            const storeAllowFrom = await readStoreAllowFromForDmPolicy({
              provider: "pulseboard",
              accountId: account.accountId,
              dmPolicy,
            });
            const { effectiveDmAllowFrom } = resolveEffectiveAllowFromLists({
              allowFrom: account.config.allowFrom,
              storeAllowFrom,
              dmPolicy,
            });
            const normalizedEffective = normalizePulseBoardAllowlist(effectiveDmAllowFrom);

            if (dmPolicy === "pairing") {
              const senderAllowed = resolvePulseBoardSenderAllowed({
                senderId: message.senderId,
                allowFrom: [...storeAllowFrom, ...normalizedEffective],
              });
              if (!senderAllowed) {
                // Issue a pairing challenge.
                const pairingCode = await pairingController.issueChallenge({
                  senderId: message.senderId,
                  reply: async (challengeText) => {
                    await sendMessagePulseBoard(
                      message.senderUsername,
                      challengeText,
                      { cfg, accountId: account.accountId },
                    );
                  },
                }).catch((err) => {
                  logger.warn?.(`[${account.accountId}] pairing challenge error: ${String(err)}`);
                  return null;
                });
                void pairingCode; // pairing challenge issued; skip dispatching this message
                continue;
              }
            } else if (dmPolicy === "allowlist") {
              const senderAllowed = resolvePulseBoardSenderAllowed({
                senderId: message.senderId,
                allowFrom: normalizedEffective,
              });
              if (!senderAllowed) {
                logInboundDrop({
                  channel: "pulseboard",
                  accountId: account.accountId,
                  reason: "sender not in allowlist",
                  target: message.target,
                });
                continue;
              }
            }
            // dmPolicy === "open" → allow all
          }

          await dispatchPulseBoardMessage({
            message,
            core: core as PluginRuntime,
            cfg,
            accountId: account.accountId,
            username: account.username,
            statusSink: opts.statusSink,
          }).catch((err) => {
            logger.error(`[${account.accountId}] dispatch error for message ${message.messageId}: ${String(err)}`);
          });
        }
      } catch (err) {
        if (stopped || opts.abortSignal?.aborted) {
          break;
        }
        logger.warn?.(`[${account.accountId}] PulseBoard poll error: ${String(err)}`);
        // Brief back-off before retrying.
        await new Promise<void>((resolve) => setTimeout(resolve, 5000));
      }
    }
  })().catch((err) => {
    logger.error(`[${account.accountId}] PulseBoard monitor loop fatal error: ${String(err)}`);
  });

  void runtime; // suppress unused variable warning
  void PAIRING_APPROVED_MESSAGE; // referenced via pairing flow above

  return {
    stop: () => {
      stopped = true;
    },
  };
}

