import { describe, expect, it } from "vitest";
import {
  isBoardTarget,
  isDmTarget,
  looksLikePulseBoardTargetId,
  normalizePulseBoardAllowEntry,
  normalizePulseBoardAllowlist,
  normalizePulseBoardBoardId,
  normalizePulseBoardMessagingTarget,
  resolvePulseBoardSenderAllowed,
} from "./normalize.js";

describe("isBoardTarget", () => {
  it("returns true for # targets", () => {
    expect(isBoardTarget("#general")).toBe(true);
    expect(isBoardTarget("#support")).toBe(true);
  });

  it("returns false for non-board targets", () => {
    expect(isBoardTarget("alice")).toBe(false);
    expect(isBoardTarget("@alice")).toBe(false);
  });
});

describe("isDmTarget", () => {
  it("returns true for @ targets", () => {
    expect(isDmTarget("@alice")).toBe(true);
  });

  it("returns false for board targets", () => {
    expect(isDmTarget("#general")).toBe(false);
    expect(isDmTarget("alice")).toBe(false);
  });
});

describe("normalizePulseBoardMessagingTarget", () => {
  it("strips pulseboard: prefix", () => {
    expect(normalizePulseBoardMessagingTarget("pulseboard:#general")).toBe("#general");
    expect(normalizePulseBoardMessagingTarget("pulseboard:alice")).toBe("alice");
  });

  it("handles board: prefix and ensures # prefix", () => {
    expect(normalizePulseBoardMessagingTarget("board:general")).toBe("#general");
    expect(normalizePulseBoardMessagingTarget("board:#general")).toBe("#general");
  });

  it("handles user: prefix", () => {
    expect(normalizePulseBoardMessagingTarget("user:alice")).toBe("alice");
  });

  it("returns bare target unchanged when valid", () => {
    expect(normalizePulseBoardMessagingTarget("#general")).toBe("#general");
    expect(normalizePulseBoardMessagingTarget("alice")).toBe("alice");
  });

  it("returns undefined for empty or invalid targets", () => {
    expect(normalizePulseBoardMessagingTarget("")).toBeUndefined();
    expect(normalizePulseBoardMessagingTarget("   ")).toBeUndefined();
    expect(normalizePulseBoardMessagingTarget("has spaces")).toBeUndefined();
  });
});

describe("looksLikePulseBoardTargetId", () => {
  it("returns true for valid target ids", () => {
    expect(looksLikePulseBoardTargetId("#general")).toBe(true);
    expect(looksLikePulseBoardTargetId("alice")).toBe(true);
    expect(looksLikePulseBoardTargetId("@alice")).toBe(true);
    expect(looksLikePulseBoardTargetId("my-board_1")).toBe(true);
  });

  it("returns false for empty or invalid inputs", () => {
    expect(looksLikePulseBoardTargetId("")).toBe(false);
    expect(looksLikePulseBoardTargetId("has spaces")).toBe(false);
  });
});

describe("normalizePulseBoardAllowEntry", () => {
  it("lowercases and strips prefixes", () => {
    expect(normalizePulseBoardAllowEntry("Alice")).toBe("alice");
    expect(normalizePulseBoardAllowEntry("pulseboard:alice")).toBe("alice");
    expect(normalizePulseBoardAllowEntry("user:Alice")).toBe("alice");
    expect(normalizePulseBoardAllowEntry("@Alice")).toBe("alice");
  });

  it("returns empty string for empty input", () => {
    expect(normalizePulseBoardAllowEntry("")).toBe("");
    expect(normalizePulseBoardAllowEntry("   ")).toBe("");
  });
});

describe("normalizePulseBoardAllowlist", () => {
  it("normalizes all entries and filters empty", () => {
    expect(normalizePulseBoardAllowlist(["Alice", "@Bob", "user:Charlie", ""])).toEqual([
      "alice",
      "bob",
      "charlie",
    ]);
  });

  it("returns empty array when given nothing", () => {
    expect(normalizePulseBoardAllowlist()).toEqual([]);
    expect(normalizePulseBoardAllowlist([])).toEqual([]);
  });
});

describe("normalizePulseBoardBoardId", () => {
  it("adds # prefix when missing", () => {
    expect(normalizePulseBoardBoardId("general")).toBe("#general");
    expect(normalizePulseBoardBoardId("#general")).toBe("#general");
  });

  it("returns empty string for empty input", () => {
    expect(normalizePulseBoardBoardId("")).toBe("");
    expect(normalizePulseBoardBoardId("   ")).toBe("");
  });
});

describe("resolvePulseBoardSenderAllowed", () => {
  it("allows when wildcard is present", () => {
    expect(
      resolvePulseBoardSenderAllowed({ senderId: "anyone", allowFrom: ["*"] }),
    ).toBe(true);
  });

  it("allows when sender is in the list", () => {
    expect(
      resolvePulseBoardSenderAllowed({ senderId: "alice", allowFrom: ["alice", "bob"] }),
    ).toBe(true);
  });

  it("blocks when sender is not in the list", () => {
    expect(
      resolvePulseBoardSenderAllowed({ senderId: "charlie", allowFrom: ["alice", "bob"] }),
    ).toBe(false);
  });

  it("blocks when allowlist is empty", () => {
    expect(
      resolvePulseBoardSenderAllowed({ senderId: "alice", allowFrom: [] }),
    ).toBe(false);
  });

  it("is case-insensitive", () => {
    expect(
      resolvePulseBoardSenderAllowed({ senderId: "Alice", allowFrom: ["alice"] }),
    ).toBe(true);
  });

  it("strips leading @ when comparing", () => {
    expect(
      resolvePulseBoardSenderAllowed({ senderId: "@alice", allowFrom: ["alice"] }),
    ).toBe(true);
  });
});

