import { describe, expect, it } from "vitest";
import { PulseBoardChannelConfigSchema } from "./config-schema.js";

describe("PulseBoardChannelConfigSchema", () => {
  it("parses a minimal valid config", () => {
    const result = PulseBoardChannelConfigSchema.safeParse({
      pulseboard: {
        token: "tok-123",
        username: "alice",
        serverUrl: "https://boards.example.com",
      },
    });
    expect(result.success).toBe(true);
  });

  it("allows boards list", () => {
    const result = PulseBoardChannelConfigSchema.safeParse({
      pulseboard: {
        token: "tok-123",
        username: "alice",
        serverUrl: "https://boards.example.com",
        boards: ["#general", "#ops"],
      },
    });
    expect(result.success).toBe(true);
  });

  it("allows allowFrom list", () => {
    const result = PulseBoardChannelConfigSchema.safeParse({
      pulseboard: {
        token: "tok-123",
        username: "alice",
        serverUrl: "https://boards.example.com",
        allowFrom: ["bob", "charlie"],
      },
    });
    expect(result.success).toBe(true);
  });

  it("rejects open dmPolicy without wildcard allowFrom", () => {
    const result = PulseBoardChannelConfigSchema.safeParse({
      pulseboard: {
        token: "tok-123",
        username: "alice",
        serverUrl: "https://boards.example.com",
        dmPolicy: "open",
        allowFrom: ["bob"],
      },
    });
    expect(result.success).toBe(false);
  });

  it("accepts open dmPolicy with wildcard allowFrom", () => {
    const result = PulseBoardChannelConfigSchema.safeParse({
      pulseboard: {
        token: "tok-123",
        username: "alice",
        serverUrl: "https://boards.example.com",
        dmPolicy: "open",
        allowFrom: ["*"],
      },
    });
    expect(result.success).toBe(true);
  });

  it("allows multiple accounts", () => {
    const result = PulseBoardChannelConfigSchema.safeParse({
      pulseboard: {
        token: "tok-abc",
        username: "alice",
        serverUrl: "https://boards.example.com",
        accounts: {
          secondary: {
            token: "tok-def",
            username: "bob",
            serverUrl: "https://other.example.com",
          },
        },
      },
    });
    expect(result.success).toBe(true);
  });

  it("rejects unknown fields due to strict schema", () => {
    const result = PulseBoardChannelConfigSchema.safeParse({
      pulseboard: {
        token: "tok-123",
        username: "alice",
        serverUrl: "https://boards.example.com",
        unknownField: true,
      },
    });
    expect(result.success).toBe(false);
  });
});

