import { afterEach, beforeEach, describe, expect, it, vi } from "vitest";

// We test send.ts by stubbing the fetch global and runtime.
const mockRuntime = {
  config: {
    loadConfig: vi.fn(() => ({
      channels: {
        pulseboard: {
          token: "tok-test",
          username: "testuser",
          serverUrl: "https://boards.example.com",
        },
      },
    })),
  },
  channel: {
    activity: {
      record: vi.fn(),
    },
  },
};

vi.mock("./runtime.js", () => ({
  getPulseBoardRuntime: vi.fn(() => mockRuntime),
}));

const mockFetch = vi.fn();
vi.stubGlobal("fetch", mockFetch);

describe("sendMessagePulseBoard", () => {
  beforeEach(() => {
    vi.clearAllMocks();
    mockFetch.mockResolvedValue({
      ok: true,
      json: async () => ({ messageId: "msg-1" }),
    });
  });

  afterEach(() => {
    vi.clearAllMocks();
  });

  it("sends a direct message to the users endpoint", async () => {
    const { sendMessagePulseBoard } = await import("./send.js");
    const result = await sendMessagePulseBoard("alice", "Hello Alice");
    expect(mockFetch).toHaveBeenCalledOnce();
    const [url, opts] = mockFetch.mock.calls[0] as [string, RequestInit];
    expect(url).toContain("/api/v1/users/alice/messages");
    expect(opts?.method).toBe("POST");
    expect(JSON.parse(opts?.body as string)).toEqual({ text: "Hello Alice" });
    expect(result.messageId).toBe("msg-1");
    expect(result.target).toBe("alice");
  });

  it("sends a board message to the boards endpoint", async () => {
    const { sendMessagePulseBoard } = await import("./send.js");
    const result = await sendMessagePulseBoard("#general", "Hello board");
    const [url] = mockFetch.mock.calls[0] as [string, RequestInit];
    expect(url).toContain("/api/v1/boards/general/messages");
    expect(result.target).toBe("#general");
  });

  it("throws for empty message text", async () => {
    const { sendMessagePulseBoard } = await import("./send.js");
    await expect(sendMessagePulseBoard("alice", "   ")).rejects.toThrow(
      "Message must be non-empty",
    );
  });

  it("throws for invalid target", async () => {
    const { sendMessagePulseBoard } = await import("./send.js");
    await expect(sendMessagePulseBoard("has spaces", "hello")).rejects.toThrow(
      "Invalid PulseBoard target",
    );
  });

  it("throws when HTTP response is not ok", async () => {
    mockFetch.mockResolvedValueOnce({
      ok: false,
      status: 403,
      statusText: "Forbidden",
    });
    const { sendMessagePulseBoard } = await import("./send.js");
    await expect(sendMessagePulseBoard("alice", "hello")).rejects.toThrow("HTTP 403");
  });

  it("records outbound activity after a successful send", async () => {
    const { sendMessagePulseBoard } = await import("./send.js");
    await sendMessagePulseBoard("alice", "hi");
    expect(mockRuntime.channel.activity.record).toHaveBeenCalledWith(
      expect.objectContaining({ direction: "outbound", channel: "pulseboard" }),
    );
  });
});

