    expect(result.messageId).toBe("msg-1");
    expect(result.target).toBe("alice");
  });

  it("sends a board message to the boards endpoint", async () => {
    const { sendMessagePulseBoard } = await import("./send.js");
    const result = await sendMessagePulseBoard("#general", "Hello board");
    const [url] = mockFetch.mock.calls[0] as [string, RequestInit];
