import { describe, expect, it, vi } from "vitest";

// Minimal smoke-tests for the PulseBoard channel plugin shape.
// Full gateway and dispatch coverage is in the IRC plugin's pattern;
// these verify the plugin is structurally valid.

vi.mock("./runtime.js", () => ({
  getPulseBoardRuntime: vi.fn(() => {
    throw new Error("PulseBoard runtime not initialized");
  }),
  setPulseBoardRuntime: vi.fn(),
  clearPulseBoardRuntime: vi.fn(),
}));

describe("pulseBoardPlugin", () => {
  it("has the expected channel id", async () => {
    const { pulseBoardPlugin } = await import("./channel.js");
    expect(pulseBoardPlugin.id).toBe("pulseboard");
  });

  it("declares direct and group chat types", async () => {
    const { pulseBoardPlugin } = await import("./channel.js");
    expect(pulseBoardPlugin.capabilities?.chatTypes).toContain("direct");
    expect(pulseBoardPlugin.capabilities?.chatTypes).toContain("group");
  });

  it("does not declare media support", async () => {
    const { pulseBoardPlugin } = await import("./channel.js");
    expect(pulseBoardPlugin.capabilities?.media).toBe(false);
  });

  it("has a setup adapter", async () => {
    const { pulseBoardPlugin } = await import("./channel.js");
    expect(pulseBoardPlugin.setup).toBeDefined();
    expect(typeof pulseBoardPlugin.setup.applyAccountConfig).toBe("function");
  });

  it("has a setup wizard", async () => {
    const { pulseBoardPlugin } = await import("./channel.js");
    expect(pulseBoardPlugin.setupWizard).toBeDefined();
    expect(pulseBoardPlugin.setupWizard?.channel).toBe("pulseboard");
  });

  it("has outbound text send configured", async () => {
    const { pulseBoardPlugin } = await import("./channel.js");
    expect(pulseBoardPlugin.outbound?.sendText).toBeDefined();
  });

  it("has a configSchema", async () => {
    const { pulseBoardPlugin } = await import("./channel.js");
    expect(pulseBoardPlugin.configSchema).toBeDefined();
  });

  it("has a pairing adapter with idLabel", async () => {
    const { pulseBoardPlugin } = await import("./channel.js");
    expect(pulseBoardPlugin.pairing?.idLabel).toBe("pulseBoardUser");
  });

  it("normalizeTarget returns undefined for empty string", async () => {
    const { pulseBoardPlugin } = await import("./channel.js");
    const normalized = pulseBoardPlugin.messaging?.normalizeTarget?.("");
    expect(normalized).toBeUndefined();
  });

  it("normalizeTarget strips pulseboard: prefix", async () => {
    const { pulseBoardPlugin } = await import("./channel.js");
    const normalized = pulseBoardPlugin.messaging?.normalizeTarget?.("pulseboard:#general");
    expect(normalized).toBe("#general");
  });

  it("looksLikeId returns true for valid board/user targets", async () => {
    const { pulseBoardPlugin } = await import("./channel.js");
    const looksLike = pulseBoardPlugin.messaging?.targetResolver?.looksLikeId;
    expect(looksLike?.("#general")).toBe(true);
    expect(looksLike?.("alice")).toBe(true);
    expect(looksLike?.("")).toBe(false);
  });
});
